final:
// // This comment suggests that q should be set to 1 when a and b are both 0
module top_module (
    input a,
    input b,
    output reg q
);    always @(*) begin
        case ({a, b})
            2'b11: q = 1'b0;
            2'b01: q = 1'b0;
            2'b00: q = 1'b0;
            2'b10: q = 1'b1;
        endcase
    end
endmodule
